@use '../../styles/tokens' as *;

.loading-bar {
  position: absolute;
  top: $search-bar-height;
  left: 0;
  right: 0;
  height: 2px;
  overflow: hidden;
  z-index: 1;
  opacity: 0;
  transition: opacity $transition-normal ease-in-out;

  &--visible {
    opacity: 1;
  }
}

.loading-bar__indicator {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    90deg,
    transparent 0%,
    $color-accent 30%,
    $color-accent-hover 50%,
    $color-accent 70%,
    transparent 100%
  );
  background-size: 200% 100%;
  animation: loading-bar-slide 1.5s ease-in-out infinite;
}

@keyframes loading-bar-slide {
  0% {
    background-position: 200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

